from dataclasses import dataclass
from datetime import date
from typing import Optional

@dataclass
class MilestoneScorecard:
    milestone_id: str
    total_teams: int
    green_teams: int
    total_criteria: int
    passed_criteria: int
    target_date: date
    actual_date: Optional[date]
    replan_count: int

    @property
    def readiness_rate(self) -> float:
        return self.green_teams / self.total_teams if self.total_teams else 0.0

    @property
    def criteria_pass_rate(self) -> float:
        return self.passed_criteria / self.total_criteria if self.total_criteria else 0.0

    @property
    def date_variance_days(self) -> Optional[int]:
        if self.actual_date is None:
            return None
        return (self.actual_date - self.target_date).days

    def rag(self) -> str:
        v = self.date_variance_days or 0
        if (self.readiness_rate >= 0.9 and
                self.criteria_pass_rate == 1.0 and
                v == 0 and
                self.replan_count == 0):
            return "GREEN"
        if self.readiness_rate < 0.75 or self.criteria_pass_rate < 0.9 or v > 5 or self.replan_count >= 2:
            return "RED"
        return "AMBER"

    def summary_line(self) -> str:
        v = f"+{self.date_variance_days}d" if self.date_variance_days else "on-time"
        return (f"[{self.milestone_id}] {self.rag()}  "
                f"readiness={self.readiness_rate:.0%}  "
                f"criteria={self.criteria_pass_rate:.0%}  "
                f"date={v}  replans={self.replan_count}")
